SELECT 


,	RNUM
FROM (
	SELECT


		,	ROWNUM RNUM FROM (
		SELECT


		FROM BIF.TB_BATCH_SVC_BAS A


			AND A.SIF_ID LIKE '%' || #{sifId, jdbcType=VARCHAR} || '%'


			AND A.SSYSTEM_NM LIKE '%' || #{ssystemNm, jdbcType=VARCHAR} || '%'

		ORDER BY A.BAT_MST_SEQ DESC
	) A WHERE ROWNUM <= #{lastIndex}
) A WHERE RNUM >= #{firstIndex}
